"use strict";(globalThis.webpackChunksap_architecture_center=globalThis.webpackChunksap_architecture_center||[]).push([[52675],{54515(e){e.exports=JSON.parse('{"tag":{"label":"Generative AI","permalink":"/architecture-center-quick-start/docs/tags/genai","description":"Generative AI is a type of AI that is capable of generating new data, such as images, videos, and text, based on the data it has been trained on.","allTagsPath":"/architecture-center-quick-start/docs/tags","count":35,"items":[{"id":"ref-arch/RA0029/a2a-and-mcp/id-ra0029-1","title":"A2A and MCP for Interoperability","description":"Learn how the Agent2Agent (A2A) and Model Context Protocol (MCP) enable a decoupled, interoperable and scalable AI agent ecosystem on SAP BTP.","permalink":"/architecture-center-quick-start/docs/ref-arch/ca1d2a3e/1"},{"id":"ref-arch/RA0029/ai-agent-identity/id-ra0029-8","title":"Agent Identity","description":"The Agent Identity is the representation of the artifacts of an agent required to follow proper Identity Access Management and especially Agent Governance procedures. The Agent Identity allows enterprises to define and restrict how and what an agent can do within certain boundaries. The Agent Identity concept allows a generic way to manage agent access to limit unnecessary \\"chatty\\" communication between agents by establishing several policy enforcement points to fail early in the process.","permalink":"/architecture-center-quick-start/docs/ref-arch/RA0029/8"},{"id":"ref-arch/RA0029/id-ra0029","title":"Agentic AI & AI Agents","description":"Build, integrate and orchestrate AI agents on SAP BTP. This reference architecture covers low-code agents with Joule Studio, pro-code agents with SAP Cloud SDK for AI, bidirectional integration with Joule and Agent2Agent (A2A) interoperability.","permalink":"/architecture-center-quick-start/docs/ref-arch/ca1d2a3e"},{"id":"ref-arch/RA0029/agentic-engineering-for-sap-extensions/id-ra0030-8","title":"Agentic Engineering for SAP Extensions","description":"Agentic engineering for BTP Extensions: context engineering, grounding through MCP servers and SDKs, multi-agent orchestration and architecture patterns for AI-native development on SAP BTP.","permalink":"/architecture-center-quick-start/docs/ref-arch/ca1d2a3e/8"},{"id":"ref-arch/RA0029/ai-agents-for-structured-data/id-ra0005-6","title":"Agents for Structured Data","description":"Transform structured data analysis with AI-powered applications, enabling real-time insights and operational efficiency.","permalink":"/architecture-center-quick-start/docs/ref-arch/ca1d2a3e/7"},{"id":"ref-arch/RA0013/joule-analytical-insights/id-ra0013-8","title":"Analytical Insights in Joule","description":"Reference Architecture for bringing analytical insights in Joule for SAP BDC using SAP Analytics Cloud JustAsk AI Service.","permalink":"/architecture-center-quick-start/docs/ref-arch/f5b6b597a6/8"},{"id":"ref-arch/RA0026/asset-inspection/id-ra0026-3","title":"Asset Inspection","description":"Learn how Embodied AI & robotics can automate asset management processes, including asset and site inspection.","permalink":"/architecture-center-quick-start/docs/ref-arch/083f2d968e/3"},{"id":"ref-arch/RA0005/basics/id-ra0005-1","title":"Basic Prompting","description":"Integrate Generative AI with SAP BTP using custom prompts for intelligent interactions and tailored AI responses.","permalink":"/architecture-center-quick-start/docs/ref-arch/e5eb3b9b1d/1"},{"id":"golden-path/ai-golden-path/build-and-deliver/build-ai-agents/readme","title":"Build AI Agents on SAP BTP","description":"Build, integrate and orchestrate AI agents on SAP BTP using Joule Studio, SAP Cloud SDK for AI, A2A and MCP protocols.","permalink":"/architecture-center-quick-start/docs/golden-path/ai-golden-path/build-and-deliver/build-ai-agents/"},{"id":"golden-path/ai-golden-path/build-and-deliver/classic-ml/readme","title":"Classic ML Scenarios","description":"Build, deploy and run machine learning use cases on SAP BTP using RPT-1, HANA Cloud PAL/APL and SAP AI Core.","permalink":"/architecture-center-quick-start/docs/golden-path/ai-golden-path/build-and-deliver/classic-ml/"},{"id":"golden-path/ai-golden-path/build-and-deliver/document-ai/readme","title":"Document AI","description":"Build, deploy and run document processing solutions using SAP Document AI on SAP BTP.","permalink":"/architecture-center-quick-start/docs/golden-path/ai-golden-path/build-and-deliver/document-ai/"},{"id":"ref-arch/RA0005/semantic-search/id-ra0005-2","title":"Embeddings & Semantic Search","description":"Improve search relevance with semantic embeddings stored in vector databases, enabling efficient similarity searches.","permalink":"/architecture-center-quick-start/docs/ref-arch/e5eb3b9b1d/2"},{"id":"ref-arch/RA0026/id-ra0026","title":"Embodied AI Agents & Robotics","description":"Embodied AI combines agentic AI with cognitive robots to automate physical world tasks, embedded within the business process context. Leverging robotics and physical AI technologies, this makes end-to-end automation possible across the digital and physical world.","permalink":"/architecture-center-quick-start/docs/ref-arch/083f2d968e"},{"id":"ref-arch/RA0024/extend-joule-with-joule-studio/id-ra0024-3","title":"Extend Joule with Joule Studio","description":"Utilize AI capabilities with Joule Studio in SAP Build. Create custom Joule Skills and AI Agents for seamless integration across SAP and non-SAP systems, driving automation and innovation.","permalink":"/architecture-center-quick-start/docs/ref-arch/06ff6062dc/3"},{"id":"ref-arch/RA0026/extensibility/id-ra0026-1","title":"Extensibility, Interoperability, and Partner Technologies","description":"Discover how SAP leverages its partner ecosystem to deliver Embodied AI at scale. Learn how partners and customers can extend Embodied AI for their use cases and get insights into interoperability.","permalink":"/architecture-center-quick-start/docs/ref-arch/083f2d968e/1"},{"id":"golden-path/ai-golden-path/build-and-deliver/genai-applications/readme","title":"GenAI Applications","description":"Build, deploy and run LLM and GenAI applications on SAP BTP using SAP AI Core, Generative AI Hub and CAP.","permalink":"/architecture-center-quick-start/docs/golden-path/ai-golden-path/build-and-deliver/genai-applications/"},{"id":"ref-arch/RA0005/id-ra0005","title":"Generative AI on SAP BTP","description":"Integrate Generative AI with SAP BTP using SAP HANA Cloud\'s Vector Engine for similarity search and advanced AI patterns.","permalink":"/architecture-center-quick-start/docs/ref-arch/e5eb3b9b1d"},{"id":"ref-arch/RA0024/joule-iam/id-ra0024-2","title":"Identity and Access Management for SAP Joule","description":"This reference architecture describes the IAM related flows for SAP Joule with SAP Build Work Zone and via the SAP Cloud Identity Services.","permalink":"/architecture-center-quick-start/docs/ref-arch/06ff6062dc/2"},{"id":"ref-arch/RA0029/integrate-ai-agents-with-joule/id-ra0029-4","title":"Integrating AI Agents with Joule","description":"Learn the architectural patterns for integrating both low-code and pro-code AI agents with Joule, SAP\'s AI copilot, for a unified user experience.","permalink":"/architecture-center-quick-start/docs/ref-arch/ca1d2a3e/4"},{"id":"ref-arch/RA0024/id-ra0024","title":"Integrating and Extending Joule","description":"Explore key topics for implementing and extending Joule, from enterprise integration with systems like SAP S/4HANA and SAP SuccessFactors to building custom skills and agents with Joule Studio and SAP BTP","permalink":"/architecture-center-quick-start/docs/ref-arch/06ff6062dc"},{"id":"ref-arch/RA0029/integrate-joule-agents-and-tools-into-your-ecosystem/id-ra0029-5","title":"Integrating Joule Agents into Your Ecosystem","description":"Learn how to expose Joule agents for consumption by third-party applications and external systems using the Agent Gateway with the A2A protocol.","permalink":"/architecture-center-quick-start/docs/ref-arch/ca1d2a3e/5"},{"id":"golden-path/ai-golden-path/build-and-deliver/joule-skills/readme","title":"Joule Skills","description":"Build, deploy and run custom Joule Skills using Joule Studio on SAP BTP for extending SAP Joule capabilities.","permalink":"/architecture-center-quick-start/docs/golden-path/ai-golden-path/build-and-deliver/joule-skills/"},{"id":"ref-arch/RA0024/joule-studio/id-ra0024-6","title":"Joule Studio","description":"SAP\u2019s AI-first low-code and pro-code development solution for generating and running custom AI agents, workflows and extensions.","permalink":"/architecture-center-quick-start/docs/ref-arch/06ff6062dc/6"},{"id":"ref-arch/RA0029/low-code-ai-agents/id-ra0029-2","title":"Low-Code AI Agents with Joule Studio","description":"Learn how to rapidly develop and deploy AI agents using the low-code capabilities of Joule Studio in SAP Build.","permalink":"/architecture-center-quick-start/docs/ref-arch/ca1d2a3e/2"},{"id":"golden-path/ai-golden-path/build-and-deliver/predictive-tabular-ai/readme","title":"Predictive & Tabular AI","description":"Build, deploy and run tabular prediction use cases with SAP-RPT-1, SAP\'s foundation model for relational business data.","permalink":"/architecture-center-quick-start/docs/golden-path/ai-golden-path/build-and-deliver/predictive-tabular-ai/"},{"id":"ref-arch/RA0029/pro-code-ai-agents/id-ra0029-3","title":"Pro-Code AI Agents on SAP BTP","description":"Learn how to build custom, pro-code AI agents on SAP BTP using SAP Cloud SDK for AI with popular frameworks like LangGraph, AutoGen and CrewAI for maximum flexibility and control over complex business logic.","permalink":"/architecture-center-quick-start/docs/ref-arch/ca1d2a3e/3"},{"id":"ref-arch/RA0026/quality-inspection/id-ra0026-5","title":"Quality Inspection","description":"Discover Embodied AI for quality inspection","permalink":"/architecture-center-quick-start/docs/ref-arch/083f2d968e/5"},{"id":"ref-arch/RA0005/retrieval-augmented-generation/id-ra0005-3","title":"Retrieval Augmented Generation (RAG)","description":"Improve LLM accuracy with Retrieval Augmented Generation (RAG) by integrating external data for enhanced precision and reduced hallucinations.","permalink":"/architecture-center-quick-start/docs/ref-arch/e5eb3b9b1d/3"},{"id":"ref-arch/RA0026/safety-inspection/id-ra0026-4","title":"Safety Inspection","description":"Discover Embodied AI for health & safety inspection","permalink":"/architecture-center-quick-start/docs/ref-arch/083f2d968e/4"},{"id":"ref-arch/RA0013/bdc-powered-by-ai-core/id-ra0013-7","title":"SAP Business Data Cloud powered by SAP AI Core","description":"Architectural patterns for integrating SAP Business Data Cloud with SAP AI Core and Generative AI Hub. Covers AI-Enhanced Data Products, model training in Databricks and serving in AI Core, batch and real-time consumption patterns, and predictive insights.","permalink":"/architecture-center-quick-start/docs/ref-arch/f5b6b597a6/7"},{"id":"ref-arch/RA0019/id-ra0019","title":"SAP IAM integration with SAP Cloud Identity Services","description":"Design authentication and role management flows for SAP SaaS with SAP Cloud Identity Services.","permalink":"/architecture-center-quick-start/docs/ref-arch/20c6b29b1e"},{"id":"ref-arch/RA0024/sap-joule-landscape-recommendation/id-ra0024-5","title":"SAP Joule Landscape Recommendation","description":"Recommended SAP BTP Subaccount model setup for unified Joule experience within a 3-staged landscape","permalink":"/architecture-center-quick-start/docs/ref-arch/06ff6062dc/5"},{"id":"golden-path/ai-golden-path/technology-overview/readme","title":"Technology Decision Tree for AI","description":"A structured decision framework for selecting the right AI approach on SAP BTP, covering relational foundation models, classic ML, LLMs and AI agents.","permalink":"/architecture-center-quick-start/docs/golden-path/ai-golden-path/technology-overview/"},{"id":"ref-arch/RA0005/vibe-code-with-cline/id-ra0005-6","title":"Vibe Coding with Cline and SAP AI Core","description":"Learn how to set up and use Cline, an autonomous coding agent, with SAP AI Core to accelerate your development workflows.","permalink":"/architecture-center-quick-start/docs/ref-arch/e5eb3b9b1d/10"},{"id":"ref-arch/RA0026/warehouse-pick-place/id-ra0026-2","title":"Warehouse Pick & Place","description":"Learn how Embodied AI & robotics can automate warehouse operations for picking, placing, sorting, and other warehouse tasks.","permalink":"/architecture-center-quick-start/docs/ref-arch/083f2d968e/2"}],"unlisted":false}}')}}]);